
describe('TRS Homepage', () => {
  beforeEach(() => {
    cy.visit('/');
  });

  it('should load homepage successfully', () => {
    cy.title().should('contain', 'TRS Web');
    cy.get('h1').should('contain', 'Welcome to TRS Web');
    cy.get('[data-cy="tourvest-heading"]').should('contain', 'Tourvest Retail Services');
  });

  it('should display navigation elements', () => {
    cy.get('[data-cy="home-link"]').should('be.visible');
    cy.get('[data-cy="menu-toggle"]').should('be.visible');
    cy.get('[data-cy="theme-toggle"]').should('be.visible');
    cy.get('[data-cy="sign-in-button"]').should('be.visible');
  });

  it('should have functional Get Started button', () => {
    cy.get('[data-cy="get-started-button"]').should('be.visible');
    cy.get('[data-cy="get-started-button"]').click();
    // Add assertion based on expected behavior
    cy.url().should('include', '/get-started'); // or appropriate route
  });

  it('should handle theme toggle', () => {
    // Test light to dark theme
    cy.get('body').then(($body) => {
      const initialTheme = $body.attr('data-theme') || 'light';
      cy.toggleTheme();
      cy.get('body').should('not.have.attr', 'data-theme', initialTheme);
    });
  });

  it('should handle menu toggle', () => {
    // Test mobile menu toggle
    cy.viewport('iphone-6');
    cy.toggleMenu();
    cy.get('[data-cy="mobile-menu"]').should('be.visible');
    cy.toggleMenu();
    cy.get('[data-cy="mobile-menu"]').should('not.be.visible');
  });
});